// ========================================
// TRIAJUR - CÁLCULO RESCISÓRIO MVP
// ========================================

// ========================================
// 1. ENTRADA
// ========================================

const inputBruto = $input.item.json;

const dados = inputBruto.body
? inputBruto.body
: inputBruto;

// ========================================
// 2. HELPERS
// ========================================

const parseBool = (val) => {
return val === true || val === "true";
};

const round = (num) => {
return Number(num.toFixed(2));
};

// ========================================
// 3. EXTRAÇÃO DE DADOS
// ========================================

const tipo_desligamento =
dados.tipo_desligamento || "sem_justa_causa";

const data_admissao =
new Date(dados.data_admissao);

const data_saida =
new Date(dados.data_saida);

const salario_bruto =
parseFloat(dados.salario_bruto) || 0;

const aviso_previo =
dados.aviso_previo || "nao_houve";

const valor_recebido =
parseFloat(dados.valor_recebido) || 0;

const atraso_pagamento =
parseBool(dados.atraso_pagamento);

const fgts_depositado =
!(dados.fgts_depositado === false ||
dados.fgts_depositado === "false");

const ferias_vencidas =
parseBool(dados.ferias_vencidas);

const horas_extras =
parseBool(dados.horas_extras);

const doenca_ocupacional =
parseBool(dados.doenca_ocupacional);

const assedio =
parseBool(dados.assedio);

// ========================================
// 4. CÁLCULO DE TEMPO
// ========================================

const diffMs =
data_saida - data_admissao;

const diffDias = Math.floor(
diffMs / (1000 * 60 * 60 * 24)
);

const meses_totais =
Math.floor(diffDias / 30.41);

const anos_completos =
Math.floor(meses_totais / 12);

const meses_restantes =
meses_totais % 12;

const dia_saida =
data_saida.getDate();

// ========================================
// 5. SALDO DE SALÁRIO
// ========================================

const saldo_salario =
(salario_bruto / 30) * dia_saida;

// ========================================
// 6. AVISO PRÉVIO
// ========================================

let dias_aviso = 0;
let valor_aviso = 0;
let projecao_aviso = false;

if (tipo_desligamento === "sem_justa_causa") {

    dias_aviso = Math.min(
        30 + (anos_completos * 3),
        90
    );

    if (
        aviso_previo === "indenizado" ||
        aviso_previo === "nao_houve"
    ) {

        valor_aviso =
            (salario_bruto / 30) * dias_aviso;

        projecao_aviso = true;
    }

} else if (
    tipo_desligamento === "pedido_demissao" &&
    aviso_previo === "nao_cumpriu"
) {

    valor_aviso = -salario_bruto;
}

const meses_projecao =
projecao_aviso
? Math.floor(dias_aviso / 30)
: 0;

// ========================================
// 7. FÉRIAS
// ========================================

// Férias vencidas SOMENTE se confirmado

let valor_ferias_vencidas = 0;

if (ferias_vencidas) {

    valor_ferias_vencidas =
        salario_bruto * 1.3333;
}

// Férias proporcionais

let ferias_proporcionais = 0;

if (tipo_desligamento !== "justa_causa") {

    let avos_ferias =
        meses_restantes;

    // Regra dos 15 dias

    if (dia_saida >= 15) {
        avos_ferias += 1;
    }

    avos_ferias += meses_projecao;

    avos_ferias =
        Math.min(avos_ferias, 12);

    ferias_proporcionais =
        ((salario_bruto / 12) * avos_ferias) * 1.3333;
}

// ========================================
// 8. 13º PROPORCIONAL
// ========================================

let decimo_terceiro = 0;

if (tipo_desligamento !== "justa_causa") {

    let avos_13 =
        data_saida.getMonth();

    // Regra dos 15 dias

    if (dia_saida >= 15) {
        avos_13 += 1;
    }

    avos_13 += meses_projecao;

    avos_13 =
        Math.min(avos_13, 12);

    decimo_terceiro =
        (salario_bruto / 12) * avos_13;
}

// ========================================
// 9. FGTS + MULTA 40%
// ========================================

const fgts_mensal =
salario_bruto * 0.08;

const fgts_saldo_estimado =
fgts_mensal * meses_totais;

const multa_fgts =
tipo_desligamento === "sem_justa_causa"
? fgts_saldo_estimado * 0.40
: 0;

// ========================================
// 10. MULTA 477
// ========================================

const multa_477 =
atraso_pagamento
? salario_bruto
: 0;

// ========================================
// 11. TOTAL BASE
// ========================================

let total_base =
saldo_salario +
valor_aviso +
valor_ferias_vencidas +
ferias_proporcionais +
decimo_terceiro +
multa_477 +
multa_fgts;

if (total_base < 0) {
total_base = 0;
}

// ========================================
// 12. DESCONTO DO QUE JÁ RECEBEU
// ========================================

const valor_restante =
Math.max(
total_base - valor_recebido,
0
);

// ========================================
// 13. FAIXA ESTIMADA
// ========================================

const faixaMin =
total_base * 0.90;

const faixaMax =
total_base * 1.10;

// ========================================
// 14. POTENCIAIS ADICIONAIS
// ========================================

const potenciais_adicionais = [];

if (horas_extras) {

    potenciais_adicionais.push(
        "Há indícios de horas extras e reflexos."
    );
}

if (doenca_ocupacional) {

    potenciais_adicionais.push(
        "Há indícios de doença ocupacional."
    );
}

if (assedio) {

    potenciais_adicionais.push(
        "Há indícios de assédio moral."
    );
}

if (!fgts_depositado) {

    potenciais_adicionais.push(
        "Há indícios de irregularidades no FGTS."
    );
}

// ========================================
// 15. TEXTO AO CLIENTE
// ========================================

let frase_direitos = "";

if (tipo_desligamento === "sem_justa_causa") {

    frase_direitos =
        ", além do saque do FGTS com multa de 40% e possível seguro-desemprego.";
} else if (
    tipo_desligamento === "pedido_demissao"
) {

    frase_direitos =
        ". No pedido de demissão normalmente não há saque do FGTS nem seguro-desemprego.";
} else {

    frase_direitos = ".";
}

let texto_apresentacao =
"Pelo seu período na empresa e salário informado, sua rescisão pode ficar aproximadamente entre R$ " +
round(faixaMin) +
" e R$ " +
round(faixaMax) +
" líquidos" +
frase_direitos;

// Adiciona potenciais adicionais

if (potenciais_adicionais.length > 0) {

    texto_apresentacao +=
        "\n\nAlém disso:\n✅ " +
        potenciais_adicionais.join("\n✅ ");
}

// ========================================
// 16. CLASSIFICAÇÃO
// ========================================

let classificacao = "QUAL";

if (
potenciais_adicionais.length > 0 ||
valor_restante > salario_bruto
) {

    classificacao = "CALC OK";
}

// ========================================
// 17. RETORNO
// ========================================

return {
    mensagem_para_o_cliente: texto_apresentacao,
    classificacao: classificacao,
    resumo: {
        saldo_salario: round(saldo_salario),
        aviso_previo: round(valor_aviso),
        ferias_vencidas: round(valor_ferias_vencidas),
        ferias_proporcionais: round(ferias_proporcionais),
        decimo_terceiro: round(decimo_terceiro),
        multa_fgts: round(multa_fgts),
        multa_477: round(multa_477),
        total_estimado: round(total_base),
        valor_ja_recebido: round(valor_recebido),
        valor_restante_estimado: round(valor_restante),
        faixa_estimativa: {
            minimo: round(faixaMin),
            maximo: round(faixaMax)
        }
    },
    potenciais_adicionais: potenciais_adicionais
};

